index 00efd3c0eb72..e6f542aa6c8b 100644
--- a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
+++ b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
@@ -5538,6 +5538,165 @@ static void createUnreachableSwitchDefault(SwitchInst *Switch,
   }
 }

+/// If the switch condition is a call to ucmp/scmp, try to convert the switch
+/// into a direct icmp and branch on the original operands.
+static bool simplifySwitchOnCmpIntrinsic(SwitchInst *SI, IRBuilder<> &Builder) {
+  Value *Cond = SI->getCondition();
+  auto *Cmp = dyn_cast<CmpIntrinsic>(Cond);
+  if (!Cmp)
+    return false;
+
+  // Only optimize if the intrinsic has a single use (the switch itself).
+  if (!Cmp->hasOneUse())
+    return false;
+
+  // ucmp/scmp returns -1, 0, or 1. The return type must be at least i2.
+  IntegerType *Ty = cast<IntegerType>(Cond->getType());
+  if (Ty->getIntegerBitWidth() < 2)
+    return false;
+
+  ConstantInt *ConstNeg1 = ConstantInt::get(Ty, -1, /*isSigned=*/true);
+  ConstantInt *Const0 = ConstantInt::get(Ty, 0);
+  ConstantInt *Const1 = ConstantInt::get(Ty, 1);
+
+  BasicBlock *DefaultDest = SI->getDefaultDest();
+  bool HasDefault =
+      !isa<UnreachableInst>(DefaultDest->getFirstNonPHIOrDbg());
+
+  // Collect the destination for each of the three possible ucmp/scmp results.
+  // Also verify that all case values are within {-1, 0, 1}.
+  // Track whether each value has an explicit case (not using default).
+  bool HasNeg1Case = false, Has0Case = false, Has1Case = false;
+  auto getDestForValue = [&](const APInt &Val, bool &HasCase) -> BasicBlock * {
+    for (auto &Case : SI->cases()) {
+      if (Case.getCaseValue()->getValue() == Val) {
+        HasCase = true;
+        return Case.getCaseSuccessor();
+      }
+    }
+    return HasDefault ? DefaultDest : nullptr;
+  };
+
+  // Verify all case values are -1, 0, or 1.
+  for (auto &Case : SI->cases()) {
+    const APInt &Val = Case.getCaseValue()->getValue();
+    if (Val != ConstNeg1->getValue() && Val != Const0->getValue() &&
+        Val != Const1->getValue())
+      return false;
+  }
+
+  BasicBlock *DestNeg1 = getDestForValue(ConstNeg1->getValue(), HasNeg1Case);
+  BasicBlock *Dest0 = getDestForValue(Const0->getValue(), Has0Case);
+  BasicBlock *Dest1 = getDestForValue(Const1->getValue(), Has1Case);
+
+  // If any value maps to an unreachable default, bail out.
+  if (!DestNeg1 || !Dest0 || !Dest1)
+    return false;
+
+  // If all three values have explicit cases and the default is not
+  // unreachable, don't try to optimize (the switch is exhaustive and
+  // the default block may have code that other passes will handle).
+  if (HasDefault && HasNeg1Case && Has0Case && Has1Case)
+    return false;
+
+  // All three go to the same destination? Just use an unconditional branch.
+  if (DestNeg1 == Dest0 && Dest0 == Dest1) {
+    Builder.CreateBr(DestNeg1);
+    SI->eraseFromParent();
+    return true;
+  }
+
+  // Determine which predicate and true/false destinations to use.
+  CmpInst::Predicate Pred;
+  BasicBlock *TrueDest, *FalseDest;
+
+  if (DestNeg1 == Dest0 && Dest0 != Dest1) {
+    // -1 (a < b) and 0 (a == b) go to Dest0, 1 (a > b) goes to Dest1.
+    // True: a > b.
+    Pred = Cmp->getGTPredicate();
+    TrueDest = Dest1;
+    FalseDest = Dest0;
+  } else if (Dest0 == Dest1 && DestNeg1 != Dest0) {
+    // 0 (a == b) and 1 (a > b) go to Dest0, -1 (a < b) goes to DestNeg1.
+    // True: a < b.
+    Pred = Cmp->getLTPredicate();
+    TrueDest = DestNeg1;
+    FalseDest = Dest0;
+  } else if (DestNeg1 == Dest1 && Dest0 != DestNeg1) {
+    // -1 (a < b) and 1 (a > b) go to DestNeg1, 0 (a == b) goes to Dest0.
+    // True: a == b.
+    Pred = CmpInst::ICMP_EQ;
+    TrueDest = Dest0;
+    FalseDest = DestNeg1;
+  } else {
+    // More than 2 destinations, can't optimize.
+    return false;
+  }
+
+  Value *LHS = Cmp->getLHS();
+  Value *RHS = Cmp->getRHS();
+  Value *CmpResult = Builder.CreateICmp(Pred, LHS, RHS, "cmp");
+  Instruction *Br = Builder.CreateCondBr(CmpResult, TrueDest, FalseDest);
+
+  // Transfer metadata from the switch to the new conditional branch.
+  if (MDNode *UnpredictableMD =
+          SI->getMetadata(LLVMContext::MD_unpredictable))
+    Br->setMetadata(LLVMContext::MD_unpredictable, UnpredictableMD);
+
+  if (MDNode *ProfMD = SI->getMetadata(LLVMContext::MD_prof)) {
+    SmallVector<uint64_t, 4> Weights;
+    extractFromBranchWeightMD64(ProfMD, Weights);
+    // Weights: [default, case_0, case_1, ...]
+    // Map cases to TrueDest/FalseDest and sum weights.
+    uint64_t TrueWeight = 0, FalseWeight = 0;
+    if (SI->getDefaultDest() == TrueDest)
+      TrueWeight += Weights[0];
+    else
+      FalseWeight += Weights[0];
+    for (auto &Case : SI->cases()) {
+      uint64_t W = Weights[Case.getCaseIndex() + 1];
+      if (Case.getCaseSuccessor() == TrueDest)
+        TrueWeight += W;
+      else
+        FalseWeight += W;
+    }
+    SmallVector<uint32_t, 2> NewWeights;
+    NewWeights.push_back(TrueWeight);
+    NewWeights.push_back(FalseWeight);
+    Br->setMetadata(
+        LLVMContext::MD_prof,
+        MDBuilder(SI->getContext()).createBranchWeights(NewWeights));
+  }
+  // Prune obsolete incoming values off the successors' PHI nodes.
+  auto UpdatePHIs = [&](BasicBlock *Dest) {
+    unsigned NumEdges = 0;
+    for (auto &Case : SI->cases())
+      if (Case.getCaseSuccessor() == Dest)
+        ++NumEdges;
+    if (Dest == SI->getDefaultDest())
+      ++NumEdges;
+    for (auto BBI = Dest->begin(); isa<PHINode>(BBI); ++BBI)
+      for (unsigned I = 0, E = NumEdges > 1 ? NumEdges - 1 : 0; I != E; ++I)
+        cast<PHINode>(BBI)->removeIncomingValue(SI->getParent());
+  };
+  UpdatePHIs(TrueDest);
+  UpdatePHIs(FalseDest);
+
+  // Clean up the default block - it may have phis or other instructions before
+  // the unreachable terminator.
+  if (!HasDefault)
+    createUnreachableSwitchDefault(SI, /*DTU=*/nullptr);
+
+  // Drop the switch.
+  SI->eraseFromParent();
+
+  // If the ucmp/scmp call is now dead, remove it.
+  if (Cmp->use_empty())
+    Cmp->eraseFromParent();
+
+  return true;
+}
+
 /// Turn a switch into an integer range comparison and branch.
 /// Switches with more than 2 destinations are ignored.
 /// Switches with 1 destination are also ignored.
@@ -7152,13 +7311,15 @@ bool SimplifyCFGOpt::simplifySwitch(SwitchInst *SI, IRBuilder<> &Builder) {
       if (foldValueComparisonIntoPredecessors(SI, Builder))
         return requestResimplify();
   }
+  // Try to transform a switch on ucmp/scmp into an icmp and a branch.
+  if (simplifySwitchOnCmpIntrinsic(SI, Builder))
+    return requestResimplify();

   // Try to transform the switch into an icmp and a branch.
   // The conversion from switch to comparison may lose information on
   // impossible switch values, so disable it early in the pipeline.
   if (Options.ConvertSwitchRangeToICmp && turnSwitchRangeIntoICmp(SI, Builder))
     return requestResimplify();
-
   // Remove unreachable cases.
   if (eliminateDeadSwitchCases(SI, DTU, Options.AC, DL))
     return requestResimplify();
